const d = $json.body ?? $json;

const appName      = d.appName      || '錢錢管家';
const appVersion   = d.appVersion   || '?';
const category     = d.category     || 'General';
const message      = d.message      || '';
const contactEmail = d.contactEmail || '';
const platform     = d.platform     || '';
const osVersion    = d.osVersion    || '';
const deviceModel  = d.deviceModel  || '';
const sourcePage   = d.sourcePage   || '';
const hasImages    = d.hasImages    || 'false';
const createdAt    = d.createdAt    || new Date().toISOString();

const subject = '[' + appName + ' Feedback] ' + category + ' — v' + appVersion;
const safeMsg = message.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const html = '<div style="font-family:sans-serif;max-width:600px">'
  + '<h2 style="color:#C59B63;border-bottom:2px solid #C59B63;padding-bottom:8px">App Feedback — ' + appName + '</h2>'
  + '<table cellpadding="10" cellspacing="0" style="width:100%;border-collapse:collapse">'
  + '<tr style="background:#f0f0f0"><th align="left" style="width:130px">欄位</th><th align="left">內容</th></tr>'
  + '<tr><td><b>類別</b></td><td>' + category + '</td></tr>'
  + '<tr style="background:#fafafa"><td><b>訊息</b></td><td style="white-space:pre-wrap">' + safeMsg + '</td></tr>'
  + '<tr><td><b>聯絡信箱</b></td><td>' + (contactEmail || '未提供') + '</td></tr>'
  + '<tr style="background:#fafafa"><td><b>App 版本</b></td><td>' + appName + ' v' + appVersion + '</td></tr>'
  + '<tr><td><b>平台</b></td><td>' + platform + ' ' + osVersion + '</td></tr>'
  + '<tr style="background:#fafafa"><td><b>裝置</b></td><td>' + deviceModel + '</td></tr>'
  + '<tr><td><b>來源頁面</b></td><td>' + sourcePage + '</td></tr>'
  + '<tr style="background:#fafafa"><td><b>附圖</b></td><td>' + (hasImages === 'true' ? 'Yes' : 'No') + '</td></tr>'
  + '<tr><td><b>提交時間</b></td><td>' + createdAt + '</td></tr>'
  + '</table></div>';

return [{ json: { emailSubject: subject, emailHtml: html } }];
